import face_recognition
import numpy as np
import os
import pickle
import cv2
from flask import Flask, request, jsonify

# --- Configuration ---
# File to store the trained facial encodings and names
MODEL_FILE = 'known_faces.pkl'
# Directory where employee photos are stored for training
# Each subdirectory name within EMPLOYEE_PHOTOS_DIR will be treated as an employee's name.
# Example: employee_photos/John_Doe/john_1.jpg, employee_photos/Jane_Smith/jane_a.png
EMPLOYEE_PHOTOS_DIR = 'employee_photos'

# Global variables to store trained data
known_face_encodings = []
known_face_names = []

# --- Facial Recognition Core Logic ---

def _load_model():
    """Loads known face encodings and names from the model file."""
    global known_face_encodings, known_face_names
    if os.path.exists(MODEL_FILE):
        try:
            with open(MODEL_FILE, 'rb') as f:
                data = pickle.load(f)
                known_face_encodings = data['encodings']
                known_face_names = data['names']
            print(f"Loaded {len(known_face_names)} known faces from {MODEL_FILE}")
        except Exception as e:
            print(f"Error loading model from {MODEL_FILE}: {e}")
            known_face_encodings = []
            known_face_names = []
    else:
        print("No existing model found. Will train from scratch or wait for training request.")

def _save_model():
    """Saves known face encodings and names to the model file."""
    data = {
        'encodings': known_face_encodings,
        'names': known_face_names
    }
    try:
        with open(MODEL_FILE, 'wb') as f:
            pickle.dump(data, f)
        print(f"Saved {len(known_face_names)} known faces to {MODEL_FILE}")
    except Exception as e:
        print(f"Error saving model to {MODEL_FILE}: {e}")

def train_model():
    """
    Trains the facial recognition model using images in EMPLOYEE_PHOTOS_DIR.
    Each subdirectory name is treated as an employee's name.
    """
    global known_face_encodings, known_face_names
    known_face_encodings = []
    known_face_names = []

    if not os.path.exists(EMPLOYEE_PHOTOS_DIR):
        print(f"Error: Employee photos directory '{EMPLOYEE_PHOTOS_DIR}' not found.")
        return False

    print(f"Starting training from '{EMPLOYEE_PHOTOS_DIR}'...")
    for person_name in os.listdir(EMPLOYEE_PHOTOS_DIR):
        person_dir = os.path.join(EMPLOYEE_PHOTOS_DIR, person_name)
        if not os.path.isdir(person_dir):
            continue

        print(f"Processing employee: {person_name}")
        person_encodings = []
        for filename in os.listdir(person_dir):
            if filename.lower().endswith(('.png', '.jpg', '.jpeg', '.tiff', '.bmp', '.gif')):
                image_path = os.path.join(person_dir, filename)
                # print(f"  Loading image: {image_path}") # Uncomment for verbose logging
                try:
                    image = face_recognition.load_image_file(image_path)
                    face_locations = face_recognition.face_locations(image)
                    if face_locations:
                        # For each image, encode the first detected face.
                        # Multiple images per person help create a more robust average encoding.
                        encoding = face_recognition.face_encodings(image, face_locations)[0]
                        person_encodings.append(encoding)
                    # else:
                        # print(f"  No face found in {filename}") # Uncomment for verbose logging
                except Exception as e:
                    print(f"  Error processing {filename}: {e}")

        if person_encodings:
            # Average the encodings for a single person to create a more robust "template"
            avg_encoding = np.mean(person_encodings, axis=0)
            known_face_encodings.append(avg_encoding)
            known_face_names.append(person_name)
            print(f"  Added encoding for {person_name} (from {len(person_encodings)} images)")
        else:
            print(f"  No valid encodings found for {person_name}")

    if known_face_encodings:
        _save_model()
        print(f"Training complete. Trained on {len(known_face_names)} unique employees.")
        return True
    else:
        print("Training completed but no faces were successfully encoded.")
        return False

def recognize_face(image_bytes):
    """
    Recognizes faces in the provided image bytes.
    Returns a list of dictionaries, each containing recognition results for a detected face.
    """
    if not known_face_encodings:
        print("No known faces to compare against. Model might not be trained.")
        return {"error": "Model not trained. Please train the model first by calling /train."}, 400

    # Convert image bytes to a numpy array for OpenCV, then to a format face_recognition can use
    np_image = np.frombuffer(image_bytes, np.uint8)
    image = cv2.imdecode(np_image, cv2.IMREAD_COLOR)

    if image is None:
        return {"error": "Could not decode image. Ensure it's a valid image format."}, 400

    # Convert BGR (OpenCV default) to RGB (face_recognition expects)
    rgb_image = image[:, :, ::-1]

    face_locations = face_recognition.face_locations(rgb_image)
    face_encodings = face_recognition.face_encodings(rgb_image, face_locations)

    results = []
    # Define a tolerance for recognizing faces. Lower value means stricter match.
    # 0.6 is a common default. Adjust as needed for your office environment.
    RECOGNITION_TOLERANCE = 0.55

    for (top, right, bottom, left), face_encoding in zip(face_locations, face_encodings):
        if not known_face_encodings:
            # This should ideally not happen due to the initial check, but for safety
            results.append({
                "face_location": [top, right, bottom, left],
                "recognition_status": "No known faces available for comparison."
            })
            continue

        # Calculate distances to all known faces
        distances = face_recognition.face_distance(known_face_encodings, face_encoding)

        # Convert distances to similarity scores.
        # 1 / (1 + distance) is a simple heuristic: higher score means more similar.
        # Adding a small epsilon to distance to prevent division by zero or very large values
        # when distances are extremely close to zero.
        similarity_scores = 1 / (1 + distances + 1e-6)

        # Normalize similarity scores to get a "probability distribution"
        total_similarity = np.sum(similarity_scores)
        if total_similarity > 0:
            probabilities = similarity_scores / total_similarity
        else:
            probabilities = np.zeros_like(similarity_scores) # All zeros if no similarity

        # Combine names and probabilities into a dictionary
        probability_distribution = {
            name: float(prob) for name, prob in zip(known_face_names, probabilities)
        }

        # Find the best match based on the minimum distance
        best_match_index = np.argmin(distances)
        best_match_name = known_face_names[best_match_index]
        best_match_distance = distances[best_match_index]
        best_match_confidence_score = probability_distribution.get(best_match_name, 0.0)

        # Determine if it's a known face based on tolerance
        is_match = best_match_distance < RECOGNITION_TOLERANCE
        recognized_name = best_match_name if is_match else "unknown"

        results.append({
            "face_location": [top, right, bottom, left],
            "best_match_candidate": {
                "name": recognized_name,
                "distance_to_best_match": float(best_match_distance),
                "confidence_score_for_best_match": float(best_match_confidence_score)
            },
            "detailed_probability_distribution": probability_distribution,
            "is_known_face": bool(is_match)
        })
    return results, 200

# Load model on startup
_load_model()

# --- Flask API Setup ---
app = Flask(__name__)

# Ensure the employee photos directory exists for training
if not os.path.exists(EMPLOYEE_PHOTOS_DIR):
    os.makedirs(EMPLOYEE_PHOTOS_DIR)
    print(f"Created directory: {EMPLOYEE_PHOTOS_DIR}")
    print("Please place employee photos in subdirectories within this folder for training.")
    print("Example: employee_photos/John_Doe/john_1.jpg, employee_photos/Jane_Doe/jane_a.png")


@app.route('/train', methods=['POST'])
def train_model_endpoint():
    """
    API endpoint to trigger model training.
    Assumes employee photos are already organized in subdirectories within
    the EMPLOYEE_PHOTOS_DIR (e.g., employee_photos/John_Doe/john.jpg).
    """
    print("Received training request...")
    success = train_model()
    if success:
        return jsonify({"message": "Model training initiated successfully. Check server logs for details."}), 200
    else:
        return jsonify({"message": "Model training failed or no faces were trained. Ensure photos are present in correct directories."}), 500

@app.route('/recognize', methods=['POST'])
def recognize_face_endpoint():
    """
    API endpoint to recognize faces in an uploaded image.
    Expects a multipart/form-data request with a 'file' field containing the image.
    """
    if 'file' not in request.files:
        return jsonify({"error": "No 'file' part in the request. Please upload an image."}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({"error": "No selected file. Please provide an image file."}), 400

    if file:
        image_bytes = file.read()
        results, status_code = recognize_face(image_bytes)
        return jsonify(results), status_code
    
    return jsonify({"error": "Unknown error processing file. Please try again."}), 500

@app.route('/', methods=['GET'])
def root():
    return jsonify({"message": "Python Facial Recognition API for Office Security. "
                               "Use POST /train to train the model and POST /recognize to recognize faces."}), 200

if __name__ == '__main__':
    # For development, enable debug mode:
    # app.run(host='0.0.0.0', port=5000, debug=True)
    # For production, run with a WSGI server like Gunicorn (e.g., gunicorn -w 4 -b 0.0.0.0:5000 app:app)
    app.run(host='0.0.0.0', port=5000)